function getRequiredCards(grade: Grade): number {
  switch (grade) {
    case "C":
    case "B":
      return 3;
    case "A":
      return 5;
    case "S":
      return 5;
    default:
      return 3;
  }
}

function shuffleDeck<T>(cards: T[]): T[] {
  const arr = [...cards];
  for (let i = arr.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [arr[i], arr[j]] = [arr[j], arr[i]];
  }
  return arr;
}

// ??? Floating Stars ???
function FloatingStars() {
  const stars = useMemo(
    () => Array.from({ length: 40 }, (_, i) => ({
      id: i,
      left: `${Math.random() * 100}%`,
      top: `${Math.random() * 100}%`,
      size: Math.random() * 2.5 + 0.5,
      delay: Math.random() * 5,
      duration: Math.random() * 3 + 2,
    })),
    []
  );
  return (
    <div className="pointer-events-none fixed inset-0 overflow-hidden z-0">
      {stars.map((s) => (
        <div
          key={s.id}
          className="absolute rounded-full bg-gold-light"
          style={{ left: s.left, top: s.top, width: s.size, height: s.size, opacity: 0.3, animation: `twinkle ${s.duration}s ease-in-out ${s.delay}s infinite` }}
        />
      ))}
    </div>
  );
}

