}

function FloatingStars() {
  const stars = useMemo(
    () =>
      Array.from({ length: 30 }, (_, i) => ({
        id: i,
        left: `${Math.random() * 100}%`,
        top: `${Math.random() * 100}%`,
        size: Math.random() * 3 + 1,
        delay: Math.random() * 5,
        duration: Math.random() * 3 + 2,
      })),
    []
  );

  return (
    <div className="pointer-events-none absolute inset-0 overflow-hidden">
      {stars.map((star) => (
        <div
          key={star.id}
          className="absolute rounded-full bg-gold-light"
          style={{
            left: star.left,
            top: star.top,
            width: star.size,
            height: star.size,
            opacity: 0.4,
            animation: `twinkle ${star.duration}s ease-in-out ${star.delay}s infinite`,
          }}
        />
      ))}
    </div>
  );
}

function classifyQuestionByLocale(question: string, locale: Locale): string {
  const q = question.toLowerCase();
  if (locale === "kr") {
    if (/(?곗븷|?ы쉶|???⑥옄|?ъ옄|?곷?|?곕씫|寃고샎|?곷?諛??띾쭏??/.test(q)) return "love";
    if (/(?댁쭅|吏곸옣|?ъ뾽|痍⑥뾽|?뚯궗|??釉뚮옖??而ㅻ━???뱀쭊)/.test(q)) return "career";
    if (/(??湲덉쟾|?щЪ|?섏씡|留ㅼ텧|?ъ뾽???ъ옄|?ъ젙)/.test(q)) return "money";
    return "general";
  }
  if (locale === "jp") {
    if (/(???뗦꽋|也썬걤|壤?壤쇔Ⅳ|孃⑴툈|麗쀦똻???ｇ덧|永먨찚)/.test(q)) return "love";
    if (/(餓뺜틟|邕?겥|鴉싩ㅎ|??깵?ゃ궋|?뉔?弱김겥)/.test(q)) return "career";
    if (/(???딃뇫|?롥뀯|?뺠퀒|縕??묌걢)/.test(q)) return "money";
    return "general";
  }
  // US
  if (/(love|relationship|partner|crush|ex|marriage|dating|contact|reach out)/.test(q)) return "love";
  if (/(career|job|work|business|promotion|interview)/.test(q)) return "career";
  if (/(money|finance|abundance|wealth|income|invest)/.test(q)) return "money";
  return "general";
}

const seoData: Record<Locale, { title: string; description: string }> = {
  kr: {
    title: "?듯빀 ?먯닠 ?곷떞 ???濡?+ ?ъ＜ 援먯감 寃利?由щ뵫",
