  parsed.reading_info.card_count = cards?.length || 0;

  // tarot_reading
  if (!parsed.tarot_reading) {
    parsed.tarot_reading = {
      choihanna: null,
      monad: null,
    };
  }

  // convergence
  if (!parsed.convergence) {
